export type CustomerStatus = "VIP" | "standard";

export interface Customer {
  status: CustomerStatus;
}

/**
 * Calculates the discount amount for a given customer and order total.
 *
 * Rules (in priority order):
 *  1. VIP customers with order total > 150 receive a 15% volume discount
 *     (volume rate overrides the standard VIP rate).
 *  2. VIP customers with order total ≤ 150 receive a 20% discount.
 *  3. Standard customers receive no discount regardless of order total.
 *
 * @param customer  - The customer object containing status information.
 * @param orderTotal - The total value of the order (must be >= 0).
 * @returns The discount amount (not the discounted price).
 */
export function calculateDiscount(customer: Customer, orderTotal: number): number {
  if (customer.status === "VIP" && orderTotal > 150) {
    // Volume discount: 15% — overrides VIP rate for large orders (AC4, AC5)
    return orderTotal * 0.15;
  }

  if (customer.status === "VIP") {
    // Standard VIP discount: 20% (AC1, AC2)
    return orderTotal * 0.2;
  }

  // Standard customers receive no discount (AC3)
  return 0;
}

